package org.apache.commons.cli;

import org.junit.Test;
import static org.junit.Assert.*;
import java.util.Arrays;
import java.util.List;

/**
 * Unit tests for MissingOptionException.
 */
public class MissingOptionExceptionTest {

    @Test
    public void testConstructorIdOne() {
        List<String> list = Arrays.asList("opt1", "opt2");
        MissingOptionException ex = new MissingOptionException(1, list, "msg");
        // Should set missingOptions to provided list
        assertSame("Expected missingOptions to reference the provided list", list, ex.getMissingOptions());
    }

    @Test
    public void testConstructorIdZero() {
        List<String> list = Arrays.asList("opt1");
        MissingOptionException ex = new MissingOptionException(0, list, "msg");
        // Should leave missingOptions as null when constructorId != 1
        assertNull("Expected missingOptions to be null when constructorId != 1", ex.getMissingOptions());
    }
}

