package org.apache.commons.cli;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertNotNull;
import static org.junit.Assert.fail;

import org.junit.Test;

import java.net.URL;

/**
 * Unit tests for {@link TypeHandler#createURL(String)}.
 */
public class TypeHandlerTest {

    @Test
    public void testCreateURLValid() throws Exception {
        String s = "http://www.example.com/path";
        URL url = TypeHandler.createURL(s);
        assertNotNull(url);
        assertEquals(s, url.toString());
    }

    @Test
    public void testCreateURLInvalid() {
        String s = "not a url";
        try {
            TypeHandler.createURL(s);
            fail("Expected ParseException");
        } catch (ParseException e) {
            assertEquals("Unable to parse the URL: not a url", e.getMessage());
        }
    }
}

