package org.apache.commons.cli;

import org.junit.Test;
import static org.junit.Assert.*;

/**
 * Tests for Option.equals method.
 */
public class OptionEqualsTest {
    @Test
    public void testEqualsSameObject() {
        Option o = new Option(0, "opt", "longOpt", "desc", false, null);
        assertTrue(o.equals(o));
    }

    @Test
    public void testEqualsNull() {
        Option o = new Option(0, "opt", "longOpt", "desc", false, null);
        assertFalse(o.equals(null));
    }

    @Test
    public void testEqualsDifferentType() {
        Option o = new Option(0, "opt", "longOpt", "desc", false, null);
        assertFalse(o.equals("string"));
    }

    @Test
    public void testEqualsEqualFields() {
        Option o1 = new Option(0, "opt", "longOpt", "desc", false, null);
        Option o2 = new Option(0, "opt", "longOpt", "desc", false, null);
        assertTrue(o1.equals(o2));
    }

    @Test
    public void testEqualsDifferentOption() {
        Option o1 = new Option(0, "opt1", "longOpt", "desc", false, null);
        Option o2 = new Option(0, "opt2", "longOpt", "desc", false, null);
        assertFalse(o1.equals(o2));
    }

    @Test
    public void testEqualsDifferentLongOption() {
        Option o1 = new Option(0, "opt", "long1", "desc", false, null);
        Option o2 = new Option(0, "opt", "long2", "desc", false, null);
        assertFalse(o1.equals(o2));
    }

    @Test
    public void testEqualsNullFields() {
        Option o1 = new Option(-1, null, null, null, false, null);
        Option o2 = new Option(-1, null, null, null, false, null);
        assertTrue(o1.equals(o2));
    }
}

