import unittest

from src.main.org.apache.commons.cli.Option import Option

class TestOptionEquals(unittest.TestCase):
    def test_equals_same_object(self):
        o = Option(0, "opt", "longOpt", "desc", False, None)
        self.assertTrue(o.equals(o))

    def test_equals_none(self):
        o = Option(0, "opt", "longOpt", "desc", False, None)
        self.assertFalse(o.equals(None))

    def test_equals_different_type(self):
        o = Option(0, "opt", "longOpt", "desc", False, None)
        self.assertFalse(o.equals("string"))

    def test_equals_equal_fields(self):
        o1 = Option(0, "opt", "longOpt", "desc", False, None)
        o2 = Option(0, "opt", "longOpt", "desc", False, None)
        self.assertTrue(o1.equals(o2))

    def test_equals_different_option(self):
        o1 = Option(0, "opt1", "longOpt", "desc", False, None)
        o2 = Option(0, "opt2", "longOpt", "desc", False, None)
        self.assertFalse(o1.equals(o2))

    def test_equals_different_long_option(self):
        o1 = Option(0, "opt", "long1", "desc", False, None)
        o2 = Option(0, "opt", "long2", "desc", False, None)
        self.assertFalse(o1.equals(o2))

    def test_equals_null_fields(self):
        o1 = Option(-1, None, None, None, False, None)
        o2 = Option(-1, None, None, None, False, None)
        self.assertTrue(o1.equals(o2))

if __name__ == '__main__':
    unittest.main()

