package org.apache.commons.cli;

import org.junit.Test;
import static org.junit.Assert.*;

public class OptionDescriptionTest {

    @Test
    public void testSetDescription() {
        // initial description via static factory
        Option opt = Option.Option1("x", "desc");
        assertEquals("desc", opt.getDescription());
        // change description
        opt.setDescription("newdesc");
        assertEquals("newdesc", opt.getDescription());
        // set description to null
        opt.setDescription(null);
        assertNull(opt.getDescription());
    }
}
